"use strict";(globalThis.webpackChunkqwen_3_docs=globalThis.webpackChunkqwen_3_docs||[]).push([[317],{34(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"qwen3-contribution-journey","metadata":{"permalink":"/AI-Hub-Model-Doc/blog/qwen3-contribution-journey","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-03-14-qwen3-contribution.md","source":"@site/blog/2026-03-14-qwen3-contribution.md","title":"Deploying Qwen3.5-4B on Snapdragon","description":"The landscape of on-device AI is evolving rapidly, and the release of Qwen3-4B (often referred to as Qwen3.5 in recent community discussions) marks a significant milestone. In this post, I\u2019ll take you through the details of this state-of-the-art model and the precise workflow I followed to contribute it to the Qualcomm AI Hub Community.","date":"2026-03-14T00:00:00.000Z","tags":[{"inline":true,"label":"qwen3","permalink":"/AI-Hub-Model-Doc/blog/tags/qwen-3"},{"inline":true,"label":"snapdragon","permalink":"/AI-Hub-Model-Doc/blog/tags/snapdragon"},{"inline":true,"label":"ai-hub","permalink":"/AI-Hub-Model-Doc/blog/tags/ai-hub"}],"readingTime":1.16,"hasTruncateMarker":true,"authors":[{"name":"carrycooldude","title":"AI Contributor","url":"https://github.com/carrycooldude","imageURL":"https://github.com/carrycooldude.png","key":"carrycooldude","page":null}],"frontMatter":{"slug":"qwen3-contribution-journey","title":"Deploying Qwen3.5-4B on Snapdragon","authors":["carrycooldude"],"tags":["qwen3","snapdragon","ai-hub"]},"unlisted":false},"content":"The landscape of on-device AI is evolving rapidly, and the release of **Qwen3-4B** (often referred to as Qwen3.5 in recent community discussions) marks a significant milestone. In this post, I\u2019ll take you through the details of this state-of-the-art model and the precise workflow I followed to contribute it to the **Qualcomm AI Hub Community**.\\n\\n\x3c!-- truncate --\x3e\\n\\n## The Journey\\n\\nContributing a model to the Qualcomm AI Hub Community Space on Hugging Face requires structural precision to ensure the assets are deployable by others. \\n\\n### Why Qwen3?\\nThe Qwen3-4B model excels in **reasoning, math, and coding**, outperforming many models in its size class. On a flagship platform like the **Snapdragon 8 Elite (QCS9075)**, it delivers impressive **Time To First Token (TTFT)** and sustainable response rates.\\n\\n### The Technical Map\\n\\n```mermaid\\ngraph TD\\n    A[Model Selection] --\x3e B[AI Hub Export]\\n    B --\x3e C[W4A16 Optimization]\\n    C --\x3e D[Asset Packaging]\\n    D --\x3e E[LFS Staging]\\n    E --\x3e F[Community Upload]\\n```\\n\\n### Overcoming Challenges\\nLarge model contributions (15GB+) often hit snags. During the upload, we encountered:\\n- **Git LFS Configuration**: Ensuring `.gitattributes` correctly tracked the massive zip file.\\n- **Authentication**: Navigating Hugging Face\'s `403 Forbidden` errors by switching from fine-grained tokens to a standard **Write** token.\\n\\nStay tuned for more on-device AI guides!\\n\\n---\\n\\n*The model is now available at [qualcomm-ai-hub-community/Qwen3-4B-Instruct-carrycooldude](https://huggingface.co/qualcomm-ai-hub-community/Qwen3-4B-Instruct-carrycooldude).*"}]}}')}}]);